static bool step_dir_entry_expect(const char *path, int expected)
{
	int count = 0;
	char name[256];
	ext4_dir dir;
	const ext4_direntry *entry;
	int rc;
	char label[320];

	snprintf(label, sizeof(label), "dir_entry_get %s expect=%d", path, expected);
	print_step(label);

	rc = ext4_dir_open(&dir, path);
	if (!check_rc("ext4_dir_open", rc))
		return false;

	while ((entry = ext4_dir_entry_next(&dir)) != NULL) {
		count++;
		if (verbose) {
			memcpy(name, entry->name, entry->name_length);
			name[entry->name_length] = 0;
			printf("     %s\n", name);
		}
	}

	rc = ext4_dir_close(&dir);
	if (!check_rc("ext4_dir_close", rc))
		return false;

	if (count < 2) {
		printf("  !! expected at least . and .. entries\n");
		return false;
	}

	if ((count - 2) != expected) {
		printf("  !! directory entry count mismatch: expected=%d actual=%d\n",
		       expected, count - 2);
		return false;
	}

	return true;
}

static bool multi_fcreate(const char *path, const char *prefix, int count)
{
	int i;
	char file_path[320];

	for (i = 0; i < count; ++i) {
		ext4_file file;
		int rc;

		snprintf(file_path, sizeof(file_path), "%s%s%d", path, prefix, i);
		rc = ext4_fopen(&file, file_path, "wb+");
		if (rc != EOK)
			return check_rc("ext4_fopen(create)", rc);

		rc = ext4_fclose(&file);
		if (rc != EOK)
			return check_rc("ext4_fclose(create)", rc);
	}

	return true;
}

static bool multi_fwrite(const char *path, const char *prefix, int count, int len)
{
	int i;
	char file_path[320];

	for (i = 0; i < count; ++i) {
		ext4_file file;
		int left = len;
		int rc;

		snprintf(file_path, sizeof(file_path), "%s%s%d", path, prefix, i);
		rc = ext4_fopen(&file, file_path, "rb+");
		if (rc != EOK)
			return check_rc("ext4_fopen(write)", rc);

		while (left > 0) {
			size_t written = 0;
			size_t chunk = (size_t)(left > MAX_RW_BUFFER ? MAX_RW_BUFFER : left);

			rc = ext4_fwrite(&file, write_buffer, chunk, &written);
			if (rc != EOK)
				return check_rc("ext4_fwrite", rc);
			if (written != chunk) {
				printf("  !! short write: expected=%u actual=%u\n",
				       (unsigned)chunk, (unsigned)written);
				return false;
			}

			left -= (int)chunk;
		}

		rc = ext4_fclose(&file);
		if (rc != EOK)
			return check_rc("ext4_fclose(write)", rc);
	}

	return true;
}

static bool multi_fread(const char *path, const char *prefix, int count, int len)
{
	int i;
	char file_path[320];

	for (i = 0; i < count; ++i) {
		ext4_file file;
		int left = len;
		int rc;

		snprintf(file_path, sizeof(file_path), "%s%s%d", path, prefix, i);
		rc = ext4_fopen(&file, file_path, "rb+");
		if (rc != EOK)
			return check_rc("ext4_fopen(read)", rc);

		while (left > 0) {
			size_t read_count = 0;
			size_t chunk = (size_t)(left > MAX_RW_BUFFER ? MAX_RW_BUFFER : left);

			memset(read_buffer, 0, MAX_RW_BUFFER);
			rc = ext4_fread(&file, read_buffer, chunk, &read_count);
			if (rc != EOK)
				return check_rc("ext4_fread", rc);
			if (read_count != chunk) {
				printf("  !! short read: expected=%u actual=%u\n",
				       (unsigned)chunk, (unsigned)read_count);
				return false;
			}
			if (memcmp(read_buffer, write_buffer, chunk) != 0) {
				printf("  !! read data mismatch\n");
				return false;
			}

			left -= (int)chunk;
		}

		rc = ext4_fclose(&file);
		if (rc != EOK)
			return check_rc("ext4_fclose(read)", rc);
	}

	return true;
}

static bool multi_fremove(const char *path, const char *prefix, int count)
{
	int i;
	char file_path[320];

	for (i = 0; i < count; ++i) {
		int rc;

		snprintf(file_path, sizeof(file_path), "%s%s%d", path, prefix, i);
