static bool run_file_batch_test(int count, int size)
{
	if (!step_device_register() ||
	    !step_mount() ||
	    !step_stats_save() ||
	    !step_dir_mk(test_dir))
		return false;

	print_step("multi_fcreate");
	if (!multi_fcreate(test_dir, "/f", count))
		return false;

	print_step("multi_fwrite");
	if (!multi_fwrite(test_dir, "/f", count, size))
		return false;

	print_step("multi_fread");
	if (!multi_fread(test_dir, "/f", count, size))
		return false;

	if (!step_dir_entry_expect(test_dir, count))
		return false;

	print_step("multi_fremove");
	if (!multi_fremove(test_dir, "/f", count))
		return false;

	return step_dir_rm(test_dir) && step_stats_check() && step_umount();
}

static bool run_dir_batch_test(int count)
{
	if (!step_device_register() ||
	    !step_mount() ||
