static bool run_rw_file_test(int size)
{
	int rc;
	ext4_file file;
	uint64_t pos;
	uint64_t file_size;
	size_t processed;
	char file_path[320];

	snprintf(file_path, sizeof(file_path), "%s/test.txt", test_dir);

	if (!step_device_register() ||
	    !step_mount() ||
	    !step_stats_save() ||
	    !step_dir_mk(test_dir))
		return false;

	print_step("fopen");
	rc = ext4_fopen(&file, file_path, "wb+");
	if (!check_rc("ext4_fopen", rc))
		return false;

	pos = ext4_ftell(&file);
	file_size = ext4_fsize(&file);
	if (!expect_true("ftell=0", pos == 0) || !expect_true("fsize=0", file_size == 0))
		return false;

	print_step("fwrite");
	processed = 0;
	while (processed < (size_t)size) {
		size_t written = 0;
		size_t chunk = (size_t)size - processed;

		if (chunk > MAX_RW_BUFFER)
			chunk = MAX_RW_BUFFER;

		rc = ext4_fwrite(&file, write_buffer, chunk, &written);
		if (!check_rc("ext4_fwrite", rc))
			return false;
		if (written != chunk)
			return expect_true("full write", false);

		processed += chunk;
	}

	pos = ext4_ftell(&file);
	file_size = ext4_fsize(&file);
	if (!expect_true("ftell after write", pos == (uint64_t)size) ||
	    !expect_true("fsize after write", file_size == (uint64_t)size))
		return false;

	print_step("fseek");
	rc = ext4_fseek(&file, 0, SEEK_SET);
	if (!check_rc("ext4_fseek", rc))
		return false;

	pos = ext4_ftell(&file);
	file_size = ext4_fsize(&file);
	if (!expect_true("ftell after seek", pos == 0) ||
	    !expect_true("fsize after seek", file_size == (uint64_t)size))
		return false;

	print_step("fread");
	processed = 0;
	while (processed < (size_t)size) {
		size_t read_count = 0;
		size_t chunk = (size_t)size - processed;

		if (chunk > MAX_RW_BUFFER)
			chunk = MAX_RW_BUFFER;

		memset(read_buffer, 0, MAX_RW_BUFFER);
		rc = ext4_fread(&file, read_buffer, chunk, &read_count);
		if (!check_rc("ext4_fread", rc))
			return false;
		if (read_count != chunk)
			return expect_true("full read", false);
		if (memcmp(read_buffer, write_buffer, chunk) != 0)
			return expect_true("read compare", false);

		processed += chunk;
	}

	pos = ext4_ftell(&file);
	file_size = ext4_fsize(&file);
	if (!expect_true("ftell after read", pos == (uint64_t)size) ||
	    !expect_true("fsize after read", file_size == (uint64_t)size))
		return false;

	print_step("fclose");
	rc = ext4_fclose(&file);
	if (!check_rc("ext4_fclose", rc))
		return false;

	return step_file_remove(file_path) &&
	       step_dir_rm(test_dir) &&
	       step_stats_check() &&
	       step_umount();
}

