static bool run_named_case(const char *name)
{
	size_t i;

	for (i = 0; i < sizeof(test_cases) / sizeof(test_cases[0]); ++i) {
		if (strcmp(test_cases[i].name, name) != 0)
			continue;

		printf("\n==> %s\n", test_cases[i].title);
		return test_cases[i].run();
	}

	printf("Unknown test target: %s\n", name);
	return false;
}

