int lwext4_test_main(int argc, char **argv)
{
	bool list_only = false;
	uint64_t start_ms;
	uint64_t end_ms;
	bool ok;
	const char *env_test_dir;

	env_test_dir = getenv("LWEXT4_TEST_DIR");
	if (env_test_dir && env_test_dir[0] != '\0')
		test_dir = env_test_dir;

	if (!parse_opt(argc, argv, &list_only))
		return EXIT_FAILURE;

	if (list_only) {
		print_targets();
		return EXIT_SUCCESS;
	}

	memset(write_buffer, RW_BUFFER_PATTERN, sizeof(write_buffer));

	printf("lwext4\n");
	printf("  image: %s\n", image_name);
	printf("  target: %s\n", target_name);
	printf("  test_dir: %s\n", test_dir);

	if (!open_blockdev())
		return EXIT_FAILURE;

	start_ms = get_ms();
	ok = run_target();
	end_ms = get_ms();

	if (!ok)
		return EXIT_FAILURE;

	printf("\nall tests finished in %" PRIu64 " ms\n", end_ms - start_ms);
	return EXIT_SUCCESS;
}

static bool open_linux(void)
{
	file_dev_name_set(input_name);
	bd = file_dev_get();
	if (!bd) {
		printf("open_filedev: fail\n");
		return false;
	}
	return true;
}

static bool open_windows(void)
{
#ifdef WIN32
	file_windows_name_set(input_name);
	bd = file_windows_dev_get();
	if (!bd) {
		printf("open_winpartition: fail\n");
		return false;
	}
	return true;
#else
	printf("open_winpartition: this mode should be used only under windows "
	       "!\n");
	return false;
#endif
}

static bool open_filedev(void)
{
	return winpart ? open_windows() : open_linux();
}

static bool parse_opt(int argc, char **argv)
{
	int option_index = 0;
	int c;

	static struct option long_options[] = {
		{"input", required_argument, 0, 'i'},
		{"block", required_argument, 0, 'b'},
		{"ext", required_argument, 0, 'e'},
		{"wpart", no_argument, 0, 'w'},
		{"verbose", no_argument, 0, 'v'},
		{"version", no_argument, 0, 'x'},
		{0, 0, 0, 0}
	};

	while (-1 != (c = getopt_long(argc, argv, "i:b:e:wvx",
				      long_options, &option_index))) {
		switch (c) {
		case 'i':
			input_name = optarg;
			break;
		case 'b':
			info.block_size = atoi(optarg);
			break;
		case 'e':
			fs_type = atoi(optarg);
			break;
		case 'w':
			winpart = true;
			break;
		case 'v':
			verbose = true;
			break;
		case 'x':
			puts(VERSION);
			exit(0);
			break;
		default:
			printf("%s", usage);
			return false;
		}
	}

	switch (info.block_size) {
	case 1024:
	case 2048:
	case 4096:
		break;
	default:
		printf("parse_opt: block_size = %" PRIu32 " unsupported\n",
		       info.block_size);
		return false;
	}

	switch (fs_type) {
	case F_SET_EXT2:
	case F_SET_EXT3:
	case F_SET_EXT4:
		break;
	default:
		printf("parse_opt: fs_type = %d unsupported\n", fs_type);
		return false;
	}

	return true;
}

int lwext4_mkfs_main(int argc, char **argv)
{
	int r;

	if (!parse_opt(argc, argv)) {
		printf("parse_opt error\n");
		return EXIT_FAILURE;
	}

	if (!open_filedev()) {
		printf("open_filedev error\n");
		return EXIT_FAILURE;
	}

	if (verbose)
		ext4_dmask_set(DEBUG_ALL);

	printf("ext4_mkfs: ext%d\n", fs_type);
	r = ext4_mkfs(&fs, bd, &info, fs_type);
	if (r != EOK) {
		printf("ext4_mkfs error: %d\n", r);
		return EXIT_FAILURE;
	}

	memset(&info, 0, sizeof(struct ext4_mkfs_info));
	r = ext4_mkfs_read_info(bd, &info);
	if (r != EOK) {
		printf("ext4_mkfs_read_info error: %d\n", r);
		return EXIT_FAILURE;
	}

	printf("Created filesystem with parameters:\n");
	printf("Size: %" PRIu64 "\n", info.len);
	printf("Block size: %" PRIu32 "\n", info.block_size);
	printf("Blocks per group: %" PRIu32 "\n", info.blocks_per_group);
	printf("Inodes per group: %" PRIu32 "\n", info.inodes_per_group);
	printf("Inode size: %" PRIu32 "\n", info.inode_size);
	printf("Inodes: %" PRIu32 "\n", info.inodes);
	printf("Journal blocks: %" PRIu32 "\n", info.journal_blocks);
	printf("Features ro_compat: 0x%x\n", info.feat_ro_compat);
	printf("Features compat: 0x%x\n", info.feat_compat);
	printf("Features incompat: 0x%x\n", info.feat_incompat);
	printf("BG desc reserve: %" PRIu32 "\n", info.bg_desc_reserve_blocks);
	printf("Descriptor size: %" PRIu32 "\n", info.dsc_size);
	printf("Label: %s\n", info.label);

	printf("\nDone ...\n");
	return EXIT_SUCCESS;
}

static const char *basename_of(const char *path)
{
    const char *p;
    p = strrchr(path, '/');
    if (p) return p + 1;
    p = strrchr(path, '\\');
    if (p) return p + 1;
    return path;
}

static void print_usage(const char *prog)
{
    printf("Usage: %s <subcommand> [args...]\n", prog);
    printf("\nSubcommands:\n");
    printf("  test    Run filesystem tests (default)\n");
    printf("  mkfs    Create ext2/3/4 filesystem on image\n");
    printf("  help    Show this message\n");
    printf("\nAlternatively, invoke via symlink name:\n");
    printf("  lwext4-test [args]   -> test mode\n");
    printf("  lwext4-mkfs [args]   -> mkfs mode\n");
}

int main(int argc, char **argv)
{
    const char *base = basename_of(argv[0]);

    /* Busybox-style dispatch based on argv[0] */
    if (strstr(base, "mkfs")) {
        return lwext4_mkfs_main(argc, argv);
    }
    if (strstr(base, "test")) {
        return lwext4_test_main(argc, argv);
    }

    /* Subcommand dispatch */
    if (argc >= 2) {
        if (strcmp(argv[1], "mkfs") == 0) {
            /* Shift argv so mkfs sees its own args */
            return lwext4_mkfs_main(argc - 1, argv + 1);
        }
        if (strcmp(argv[1], "test") == 0) {
            return lwext4_test_main(argc - 1, argv + 1);
        }
        if (strcmp(argv[1], "help") == 0 ||
            strcmp(argv[1], "--help") == 0 ||
            strcmp(argv[1], "-h") == 0) {
            print_usage(argv[0]);
            return EXIT_SUCCESS;
        }
        /* No recognized subcommand: assume test mode (pass all args through) */
    }

    /* Default: test mode */
    return lwext4_test_main(argc, argv);
}

atic inline void ext4_bcache_set_dirty(struct ext4_buf *buf) {
	ext4_bcache_set_flag(buf, BC_UPTODATE);
	ext4_bcache_set_flag(buf, BC_DIRTY);
}

atic inline void ext4_bcache_clear_dirty(struct ext4_buf *buf) {
	ext4_bcache_clear_flag(buf, BC_UPTODATE);
	ext4_bcache_clear_flag(buf, BC_DIRTY);
}

atic inline void
ext4_bcache_insert_dirty_node(struct ext4_bcache *bc, struct ext4_buf *buf) {
	if (!buf->on_dirty_list) {
		SLIST_INSERT_HEAD(&bc->dirty_list, buf, dirty_node);
		buf->on_dirty_list = true;
	}
}

atic inline void
ext4_bcache_remove_dirty_node(struct ext4_bcache *bc, struct ext4_buf *buf) {
	if (buf->on_dirty_list) {
		SLIST_REMOVE(&bc->dirty_list, buf, ext4_buf, dirty_node);
		buf->on_dirty_list = false;
	}
}

static inline void ext4_bmap_bit_set(uint8_t *bmap, uint32_t bit)
{
	*(bmap + (bit >> 3)) |= (1 << (bit & 7));
}

static inline void ext4_bmap_bit_clr(uint8_t *bmap, uint32_t bit)
{
	*(bmap + (bit >> 3)) &= ~(1 << (bit & 7));
}

static inline bool ext4_bmap_is_bit_set(uint8_t *bmap, uint32_t bit)
{
	return (*(bmap + (bit >> 3)) & (1 << (bit & 7)));
}

static inline bool ext4_bmap_is_bit_clr(uint8_t *bmap, uint32_t bit)
{
	return !ext4_bmap_is_bit_set(bmap, bit);
}

